require("util")
local AIHelper = {}

function AIHelper.get_enemy_unit_settings(group_size)
    return {
        destroy_when_commands_fail = true,
        allow_try_return_to_spawner = true,
        size_in_group = group_size or 1
    }
end

function AIHelper.get_controllable_unit_setting(group_size)
    return {
        destroy_when_commands_fail = false,
        allow_try_return_to_spawner = false,
        size_in_group = group_size or 1
    }
end

